// === 2. TOKENIZACION (on-premise) ===
// Reemplaza PII por tokens ANTES de cualquier IA.
// Oculta lo irrelevante; conserva nombre+CI solo para el revisor interno.
const body = $input.item.json.body || $input.item.json;
const cliente = body.cliente || {};
let texto = (body.mensaje || '').toString();
const mapa = {};

function tokenizar(valor, prefijo) {
  if (!valor) return;
  const token = '{' + prefijo + '_001}';
  mapa[token] = valor;
  if (texto.includes(valor)) texto = texto.split(valor).join(token);
}

// PII tokenizada (no va a la IA en claro)
tokenizar(cliente.nombre, 'NAME');
tokenizar(cliente.ci, 'CI');
tokenizar(cliente.cuenta, 'ACCT');
tokenizar(cliente.telefono, 'PHONE');

return {
  json: {
    canal: body.canal || 'desconocido',
    producto: body.producto || '',
    agencia: body.agencia || '',
    mensaje_original: body.mensaje || '',
    texto_tokenizado: texto,
    mapa_tokens: mapa,
    // El revisor interno solo necesita esto (segun el banco):
    cliente_visible: { nombre: cliente.nombre || null, ci: cliente.ci || null }
  }
};

// === 3. CLASIFICACION POR REGLAS ===
// (Luego se reemplaza por una llamada a Claude para entender el contexto.)
const j = $input.item.json;
const t = (j.texto_tokenizado || '').toLowerCase();

// Producto (capa por canal/producto)
let producto = j.producto || 'desconocido';
if (t.includes('altoke') || t.includes('qr')) producto = 'altoke';
else if (t.includes('appsol')) producto = 'appSol';
else if (t.includes('solnet')) producto = 'Solnet';

let tipo = 'queja';
let severidad = 'baja';
let categoria = 'general';

// --- PASO 1: QUEJAS CONOCIDAS (tienen prioridad; son casos del playbook) ---
// El banco las definio como bajo impacto con solucion operativa conocida.
const quejasConocidas = [
  { patron: ['cambie de celular','cambié de celular','cambie de dispositivo','cambié de dispositivo','nuevo celular','nuevo dispositivo','cambie mi telefono'], categoria: 'acceso' },
  { patron: ['escanear','carnet','extranjero','re-escanear','volver a escanear'], categoria: 'acceso' },
  { patron: ['sigue saliendo la deuda','sigue la deuda','no me han devuelto','ya pague','ya pagué','pague y sigue','pagué y sigue'], categoria: 'transacciones' }
];
let esQuejaConocida = false;
for (const q of quejasConocidas) {
  if (q.patron.some(p => t.includes(p))) { esQuejaConocida = true; categoria = q.categoria; break; }
}

if (!esQuejaConocida) {
  // --- PASO 2: INCIDENTE (falla generalizada de funcion critica) ---
  const senalesIncidente = [
    'no puedo entrar','no puedo iniciar','no inicia','no carga','no funciona',
    'caido','caida','caída','no puedo transferir','no me deja transferir','qr no',
    'no procesa','error general','se cae','app caida','no puedo acceder','no anda','nadie puede'
  ];
  const criticas = ['login','iniciar sesion','iniciar sesión','transferencia','transferir','qr','ach'];
  if (senalesIncidente.some(k => t.includes(k))) { tipo = 'incidente'; severidad = 'alta'; }
  if (criticas.some(k => t.includes(k)) && (t.includes('no ') || t.includes('error') || t.includes('falla'))) { tipo = 'incidente'; severidad = 'alta'; }

  // categoria operativa (del Excel de categorizacion)
  if (t.includes('transfer') || t.includes('pago') || t.includes('qr')) categoria = 'transacciones';
  else if (t.includes('iniciar') || t.includes('login') || t.includes('entrar') || t.includes('sesion') || t.includes('acceso')) categoria = 'acceso';
  else if (t.includes('lento') || t.includes('demora') || t.includes('timeout')) categoria = 'rendimiento';
  else if (t.includes('saldo') || t.includes('movimiento') || t.includes('comprobante')) categoria = 'datos';
}

return { json: { ...j, tipo, severidad, producto, categoria } };

// === 5a. CAMINO INCIDENTE: armar Paquete de Incidente ===
const j = $input.item.json;
const id = 'INC-' + Date.now().toString().slice(-5);
const equipo = j.producto === 'altoke' ? 'Equipo Pagos/QR' : (j.producto === 'appSol' ? 'DevOps appSol' : 'DevOps');

return { json: {
  resultado: 'INCIDENTE',
  caso_id: id,
  paquete_para_desarrollo: {
    que_falla: j.categoria + ' en ' + j.producto,
    producto: j.producto,
    severidad: j.severidad,
    afectados: 1,                         // se incrementa al agrupar casos iguales
    datos_para_reproducir: {
      canal: j.canal,
      producto: j.producto,
      agencia: j.agencia,
      texto_tokenizado: j.texto_tokenizado
    },
    equipo_asignado: equipo,
    estado: 'En análisis'
  },
  respuesta_cliente: 'Recibimos tu reporte. Lo vinculamos al incidente ' + id + '. Estamos trabajando en ello y te avisaremos por este mismo canal. Estado: En análisis.'
} };

// === 5b. CAMINO QUEJA: respuesta desde Playbook Vivo ===
// (Playbook embebido para el demo; luego sale de la base versionada.)
const j = $input.item.json;
const playbook = {
  acceso: {
    pasos: ['1. Cierra y vuelve a abrir la app', '2. Si cambiaste de dispositivo, reactiva tus tokens', '3. Si persiste, vuelve a escanear tu carnet'],
    respuesta: 'Para resolver tu acceso: reactiva tus tokens o vuelve a escanear tu carnet siguiendo los pasos. Si continúa, escríbenos.'
  },
  transacciones: {
    pasos: ['1. Verifica tu comprobante', '2. Espera el transcurso del día (conciliación)', '3. Si no se refleja, te contactamos'],
    respuesta: 'Tu operación está en proceso. Por favor espera el transcurso del día; se reflejará tras la conciliación.'
  },
  rendimiento: {
    pasos: ['1. Revisa tu conexión a internet', '2. Cierra otras apps', '3. Actualiza la app a la última versión'],
    respuesta: 'Puede ser un tema de conexión o versión. Sigue los pasos; si continúa, avísanos.'
  },
  datos: {
    pasos: ['1. Refresca la pantalla', '2. Espera unos minutos por actualización', '3. Si no aparece, te ayudamos'],
    respuesta: 'Tu información puede tardar en actualizarse. Refresca la pantalla; si no aparece, escríbenos.'
  },
  general: {
    pasos: ['1. Revisa tu conexión', '2. Actualiza la app'],
    respuesta: 'Gracias por tu consulta. Sigue los pasos indicados; si continúa, escríbenos.'
  }
};
const pb = playbook[j.categoria] || playbook.general;
const id = 'QJA-' + Date.now().toString().slice(-5);

return { json: {
  resultado: 'QUEJA',
  caso_id: id,
  producto: j.producto,
  categoria: j.categoria,
  playbook_version: 'v1',
  canal: j.canal,
  respuesta_cliente: pb.respuesta,   // MISMA respuesta en todos los canales
  pasos: pb.pasos,
  estado: 'Resuelto (autoservicio)'
} };
